import logo from './logo.svg';
import React, { useState } from 'react';
import './App.css';

function App() {

  const headleClick = () => {
    console.log('このアプリはメモ管理用のReactアプリです');

  };

  const [showForm, setShowForm] = useState(true);

  const toggleForm = () => {
    setShowForm(!showForm);
  };



  return (
    <div className="App">
      <header className="App-header">
        {/* --- アプリ概要エリア --- */}
        <h1>メモ管理アプリ</h1>
        <p>メモの作成と管理が可能アプリです</p>
        <button onClick={headleClick} style={{ padding: '10px', cursor: 'pointer' }}>
        アプリの詳細情報を出力
      </button>

        <hr /> {/* 区切り線（任意） */}

        {/* --- フォーム切り替えエリア --- */}
        <button onClick={toggleForm}>
          {showForm ? 'フォームを隠す' : 'フォームを表示する'}
        </button>

        {showForm && (
          <div className="memo-form">
            <textarea placeholder="ここにメモを書いてください" />
            <br />
            <button>保存</button>
          </div>
        )}
      </header>
    </div>
  );

}
export default App;
